<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Sand Cellular Automaton</title>
    <style>
        body {
            background-color: #000;
            color: white;
            font-family: sans-serif;
        }

        .sand-container {
            position: relative;
            width: 400px;
            height: 400px;
            margin: auto;
            border: 1px solid #ccc;
            display: flex;
            justify-content: center;
            align-items: center;
        }

        .material {
            padding: 10px;
            cursor: pointer;
        }

        .mat-sand { background-color: #e6e6e6; color: black; }
        .mat-water { background-color: #d4edda; color: white; }
        .mat-wall { background-color: #c3e6cb; color: black; }
        .mat-acid { background-color: #f8b7a5; color: white; }
        .mat-empty { background-color: #fff9c4; color: black; }

        canvas {
            border: 1px solid #ccc;
        }
    </style>
</head>
<body>
    <div id="sand" class="sand-container"></div>

    <button class="mat-sand" onclick="set(0,0,"sand")">Sand</button>
    <button class="mat-water" onclick="set(0,1,"water")">Water</button>
    <button class="mat-wall" onclick="set(0,2,"wall")">Wall</button>
    <button class="mat-acid" onclick="set(0,3,"acid")">Acid</button>
    <button class="mat-empty" onclick="set(0,4,"empty")">Empty (eraser)</button>

    <div id="grid"></div>

    <script>
        // Window simulation API
        window.sim = {
            w: 80,
            h: 80,
            tick(n): { /* deterministic */ },
            get(x, y): function() { return grid[y][x]; }, // returns material name at (x,y)
            set(x, y, material): { /* set cell at (x,y) to material */ },
            clear(): { /* empty whole grid */ }
        };

        let windowSim = {
            w: 80,
            h: 80,
            tick(n): { /* deterministic */ },
            get(x, y): function() { return grid[y][x]; }, // returns material name at (x,y)
            set(x, y, material): { /* set cell at (x,y) to material */ },
            clear(): { /* empty whole grid */ }
        };

        let grid = [];
        let w = 80;
        let h = 80;

        function initializeGrid() {
            grid = new Array(h).fill(null).map(() => new Array(w).fill(''));
            for (let i = 0; i < h; i++) {
                for (let j = 0; j < w; j++) {
                    grid[i][j] = 'empty';
                }
            }
        }

        function sandFall(x) {
            while (true) {
                let current = getMaterial(x, y);
                if (current === 'sand') break;

                let below = grid[y+1][x];
                if (below === 'empty' && y < h-1) {
                    grid[y][x] = 'sand';
                } else if (below === 'water' || below === 'acid') {
                    grid[y][x] = 'water'; // or empty? We'll set to water as per rule
                    grid[y+1][x] = 'empty';
                }
            }
        }

        function waterFall(x) {
            while (true) {
                let current = getMaterial(x, y);
                if (current === 'water') break;

                let below = grid[y+1][x];
                if (below === 'empty' && y < h-1) {
                    grid[y][x] = 'water';
                } else if (below === 'sand' || below === 'acid') {
                    // water spreads horizontally into empty cells
                    let left = grid[y+1][x-1];
                    let right = grid[y+1][x+1];
                    if (left === 'empty' && x > 0) {
                        grid[y][x] = 'water';
                        grid[y+1][x-1] = 'empty';
                    } else if (right === 'empty' && x < w-1) {
                        grid[y][x] = 'water';
                        grid[y+1][x+1] = 'empty';
                    }
                }
            }
        }

        function acidFall(x) {
            while (true) {
                let current = getMaterial(x, y);
                if (current === 'acid') break;

                let below = grid[y+1][x];
                if (below === 'empty' && y < h-1) {
                    grid[y][x] = 'acid';
                } else if (below === 'sand' || below === 'wall') {
                    // acid dissolves sand or wall
                    grid[y][x] = 'empty';
                } else if (below === 'water') {
                    grid[y][x] = 'empty';
                }
            }
        }

        function processStep() {
            for (let y = 0; y < h; y++) {
                for (let x = 0; x < w; x++) {
                    if (grid[y][x] === 'sand') sandFall(x);
                    else if (grid[y][x] === 'water') waterFall(x);
                    else if (grid[y][x] === 'acid') acidFall(x);
                }
            }
        }

        function clear() {
            for (let i = 0; i < h; i++) {
                for (let j = 0; j < w; j++) {
                    grid[i][j] = 'empty';
                }
            }
        }

        window.sim.clear();
        initializeGrid();
        window.clear();

        let animate = function() {
            processStep();
            if (h > 0 && w > 0) requestAnimationFrame(animate);
        };

        window.sim.tick(1); // start simulation

        // Material buttons set functions
        function set(x, y, material) {
            grid[y][x] = material;
        }
    </script>
</body>
</html>
